     9→private enum QuickGridPinchDebug {
    10→    static let gestureFrameBudgetMs: Double = 8
    11→    static let gestureFrameSevereBudgetMs: Double = 12
    12→
    13→    static let isEnabled: Bool = {
    14→        let processInfo = ProcessInfo.processInfo
    15→        if processInfo.environment["CEE_DEBUG_QUICKGRID_PINCH"] == "1" {
    16→            return true
    17→        }
    18→        return processInfo.arguments.contains("--debug-quickgrid-pinch")
    19→    }()
    20→
    21→    static func log(_ message: @autoclosure () -> String) {
    22→        guard isEnabled else { return }
    23→        let text = message()
    24→        GridPerfLog.log("pinch: \(text)")
    25→        fputs("[QuickGridPinch] \(text)\n", stderr)
