    73→/// NSScrollView subclass that intercepts Cmd+Scroll for grid cell size adjustment.
    74→/// NSScrollView captures scrollWheel before documentView, so subclassing is required
    75→/// (same pattern as ImageScrollView).
    76→final class GridScrollView: NSScrollView {
    77→    private final class VisibleScroller: NSScroller {
    78→        override class func scrollerWidth(for controlSize: NSControl.ControlSize,
    79→                                          scrollerStyle: NSScroller.Style) -> CGFloat {
    80→            12
    81→        }
    82→
    83→        override func drawKnobSlot(in slotRect: NSRect, highlight flag: Bool) {
    84→            let inset = slotRect.insetBy(dx: 2, dy: 2)
    85→            NSColor.white.withAlphaComponent(0.10).setFill()
    86→            NSBezierPath(roundedRect: inset, xRadius: 4, yRadius: 4).fill()
    87→        }
    88→
    89→        override func drawKnob() {
    90→            let knobRect = rect(for: .knob).insetBy(dx: 2, dy: 2)
    91→            guard knobRect.width > 0, knobRect.height > 0 else { return }
    92→            NSColor.white.withAlphaComponent(0.55).setFill()
    93→            NSBezierPath(roundedRect: knobRect, xRadius: 4, yRadius: 4).fill()
    94→        }
    95→    }
    96→
    97→    var onCmdScroll: ((CGFloat) -> Void)?
    98→    /// Read by scrollWheel to compute delta-based size. Updated by QuickGridView.
    99→    var currentCellSize: CGFloat = Constants.quickGridCellSize
   100→    /// Controls vertical scroller visibility. Set by QuickGridView.updateScrollerVisibility().
   101→    var wantsVerticalScroller: Bool = false {
   102→        didSet {
   103→            guard wantsVerticalScroller != oldValue else { return }
   104→            super.hasVerticalScroller = wantsVerticalScroller
   105→            verticalScroller?.isHidden = !wantsVerticalScroller
   106→            verticalScroller?.alphaValue = wantsVerticalScroller ? 1 : 0
   107→            verticalScroller?.needsDisplay = true
   108→            tile()
   109→            reflectScrolledClipView(contentView)
   110→            needsLayout = true
   111→        }
   112→    }
   113→
   114→    // NSCollectionView re-enables scrollers during layout passes / reloadData.
   115→    // Override to control visibility via wantsVerticalScroller property.
   116→    override var hasVerticalScroller: Bool {
   117→        get { wantsVerticalScroller }
   118→        set { /* ignore — NSCollectionView tries to enable this */ }
   119→    }
   120→    override var hasHorizontalScroller: Bool {
   121→        get { false }
   122→        set { /* ignore */ }
   123→    }
   124→
   125→    override init(frame frameRect: NSRect) {
   126→        super.init(frame: frameRect)
   127→        allowsMagnification = false  // defensive: prevent pinch event consumption
   128→        scrollerStyle = .legacy  // fixed visible when content overflows
   129→        autohidesScrollers = false
   130→        scrollerKnobStyle = .light
   131→        drawsBackground = false
   132→        super.hasHorizontalScroller = false
   133→        super.hasVerticalScroller = false
   134→        verticalScroller = VisibleScroller(frame: .zero)
   135→        verticalScroller?.controlSize = .regular
   136→        verticalScroller?.alphaValue = 0
   137→        verticalScroller?.isHidden = true
   138→    }
   139→
   140→    required init?(coder: NSCoder) {
   141→        fatalError("init(coder:) not supported")
   142→    }
   143→
   144→    override func scrollWheel(with event: NSEvent) {
   145→        guard event.modifierFlags.contains(.command) else {
   146→            super.scrollWheel(with: event)
   147→            return
   148→        }
   149→        // Cmd+Scroll → adjust grid cell size
   150→        let delta = event.scrollingDeltaY
   151→        guard abs(delta) > 0.01 else { return }
   152→
   153→        let sensitivity: CGFloat = event.hasPreciseScrollingDeltas ? 0.5 : 3.0
   154→        let newSize = currentCellSize + delta * sensitivity
   155→        onCmdScroll?(newSize)
   156→        // Do NOT call super — prevents event leaking to ImageScrollView underneath
   157→    }
   158→}
