   216→/// NSCollectionView subclass that intercepts Enter/Return at the first responder level.
   217→/// Without this, Enter events would need to propagate up the responder chain,
   218→/// which NSCollectionView may not forward reliably.
   219→private final class GridCollectionView: NSCollectionView {
   220→    var onReturn: (() -> Void)?
   221→    var onDismiss: (() -> Void)?
   222→    /// Callback for cell size changes (pinch gesture, non-animated).
   223→    /// Parameters: newSize, gesture phase (began/changed/ended/cancelled)
   224→    var onCellSizeChange: ((CGFloat, NSEvent.Phase) -> Void)?
   225→    /// Callback for animated cell size changes (keyboard shortcuts).
   226→    var onAnimatedCellSizeChange: ((CGFloat) -> Void)?
   227→    /// Callback for PageDown key
   228→    var onPageDown: (() -> Void)?
   229→    /// Callback for PageUp key
   230→    var onPageUp: (() -> Void)?
   231→    /// Current cell size — set by QuickGridView, read for incremental pinch calculation.
   232→    var currentCellSize: CGFloat = Constants.quickGridCellSize
   233→
   234→    override func keyDown(with event: NSEvent) {
   235→        let modifiers = event.modifierFlags.intersection(.deviceIndependentFlagsMask)
   236→
   237→        switch event.keyCode {
   238→        case 36, 76:  // Return / Numpad Enter
   239→            onReturn?()
   240→        case 5 where modifiers == []:  // bare G (dismiss)
   241→            onDismiss?()
   242→        case 24 where modifiers == .command || modifiers == [.command, .shift]:
   243→            // Cmd+= or Cmd+Shift+= (Cmd+) — grow by 10pt (ANSI keyCode 24)
   244→            onAnimatedCellSizeChange?(currentCellSize + 10)
   245→        case 27 where modifiers == .command:  // Cmd+- (ANSI keyCode 27) — shrink by 10pt
   246→            onAnimatedCellSizeChange?(currentCellSize - 10)
   247→        case 121:  // PageDown
   248→            onPageDown?()
   249→        case 116:  // PageUp
   250→            onPageUp?()

