507→    /// Used by keyboard navigation. Static for unit testing.
508→    /// - Parameter edgeMargin: minimum pixels outside viewport before triggering scroll.
509→    ///   Prevents micro-jitter when item is within a few pixels of the viewport edge
510→    ///   (floating-point settle, or border alignment with scrollbar geometry).
511→    /// - Parameter centered: if true, scroll so the item is vertically centered in the viewport
512→    ///   (used by zoom-end path). If false, scroll just enough to bring item to the edge.
513→    static func scrollTargetYForItem(
514→        itemFrame: CGRect,
515→        visibleRect: CGRect,
516→        documentHeight: CGFloat,
517→        edgeMargin: CGFloat = 0,
518→        centered: Bool = false
519→    ) -> CGFloat? {
520→        let isBelow = itemFrame.maxY > visibleRect.maxY + edgeMargin
521→        let isAbove = itemFrame.minY < visibleRect.minY - edgeMargin
522→        guard isBelow || isAbove else {
523→            return nil  // already visible (within edgeMargin tolerance)
524→        }
525→        let maxScrollY = max(0, documentHeight - visibleRect.height)
526→        let targetY: CGFloat
527→        if centered {
528→            targetY = itemFrame.midY - visibleRect.height / 2
529→        } else if isBelow {
530→            targetY = itemFrame.maxY - visibleRect.height
531→        } else {
532→            targetY = itemFrame.minY
533→        }
534→        return max(0, min(targetY, maxScrollY))
535→    }
